import zipfile, re
from lxml import etree
W='http://schemas.openxmlformats.org/wordprocessingml/2006/main'
q=lambda t:f'{{{W}}}{t}'
z=zipfile.ZipFile('output/settlement-agreement-markup.docx')
root=etree.fromstring(z.read('word/document.xml'))
body=root.find(q('body'))
paras=[p for p in body if p.tag==q('p')]

def accepted_text(p):
    # all w:t (incl inside w:ins), exclude w:delText
    parts=[]
    for t in p.iter(q('t')):
        parts.append(t.text or '')
    return ''.join(parts)
def original_text(p):
    # w:t NOT inside w:ins + w:delText
    parts=[]
    for r in p.iter(q('r')):
        # skip runs inside w:ins
        parent=r.getparent()
        if parent is not None and parent.tag==q('ins'): continue
        for t in r.findall(q('t')):
            parts.append(t.text or '')
    for dt in p.iter(q('delText')):
        parts.append(dt.text or '')
    return ''.join(parts)

# Find paragraphs by marker
def find(marker):
    for i,p in enumerate(paras):
        if marker in accepted_text(p) or marker in original_text(p):
            return i,p
    return None,None

checks=[
 ('(b) \"Effective Date\"','the eighth (8th) calendar day','May 5, 2025, the date first set forth above'),
 ('Accelerated Vesting of Restricted Stock Units','\$12.50','\$10.00'),
 ('Total Settlement Value','\$537,500','\$525,000'),
 ('period of','twenty-one (21)','fourteen (14)'),
 ('within the states of','Idaho.','California.'),
 ('in perpetuity','three (3) years','in perpetuity'),
]
for marker,exp_new,exp_old in checks:
    i,p=find(marker)
    if p is None:
        print('NOT FOUND:',marker); continue
    acc=accepted_text(p); orig=original_text(p)
    ok_new = exp_new.replace('\\\\','') in acc
    ok_old = exp_old.replace('\\\\','') in orig
    print(f'[{i}] {marker[:30]:32} accepted_has={ok_new} original_has={ok_old}')
    if not ok_new: print('     ACCEPTED:',acc[:200])
    if not ok_old: print('     ORIGINAL:',orig[:200])
""}

